// BenchmarkPatternCompileAndMatch benchmarks the full workflow of compiling
// a pattern and then matching against it

func BenchmarkPatternCompileAndMatch(b *testing.B) {
	patterns := []struct {
		name    string
		pattern string
		path    string
	}{
		{"SimpleLiteral", "README.md", "README.md"},
		{"SimpleWildcard", "*.go", "main.go"},
		{"DoubleWildcard", "**/*.go", "src/pkg/main.go"},
		{"ComplexPath", "**/dir/**/file*.txt", "a/b/dir/c/d/file123.txt"},
		{"DotFile", ".*", ".gitignore"},
	}

	for _, tc := range patterns {
		b.Run(tc.name, func(b *testing.B) {
			for i := 0; i < b.N; i++ {
				p := &Pattern{cleanedPattern: tc.pattern}
				if err := p.compile(); err != nil {
					b.Fatal(err)
				}
				_, err := p.match(tc.path)
				if err != nil {
					b.Fatal(err)
				}
			}
		})
	}
}

// BenchmarkPatternCompileParallel benchmarks compile() with parallel execution
// to test for any concurrency-related performance characteristics

func BenchmarkPatternCompileParallel(b *testing.B) {
	patterns := []string{
		"*.go",
		"**/*.go",
		"**/dir/**",
		"a*b*c*d*e*/f",
		"**/*_test.go",
	}

	b.RunParallel(func(pb *testing.PB) {
		i := 0
		for pb.Next() {
			p := &Pattern{cleanedPattern: patterns[i%len(patterns)]}
			if err := p.compile(); err != nil {
				b.Fatal(err)
			}
			i++
		}
	})
}
